          </CardBody>
        </Card>
      </PageSection>

      {/* Kanban Board */}
      <PageSection>
        <Card>
          <CardTitle>Feature Board</CardTitle>
          <CardBody>
            <KanbanBoard features={MOCK_FEATURES} />
          </CardBody>
        </Card>
      </PageSection>
    </Page>
  );
}

export default App;

