// Convert ANSI codes to HTML spans
function parseAnsiToHtml(text: string): string {
  // Match ANSI escape sequences
  const ansiRegex = /\x1b\[([0-9;]+)m/g;
  let result = '';
  let lastIndex = 0;
  let currentStyles: string[] = [];

  let match;
  while ((match = ansiRegex.exec(text)) !== null) {
    // Add text before the match
    if (match.index > lastIndex) {
      const textSegment = text.slice(lastIndex, match.index);
      if (currentStyles.length > 0) {
        result += `<span style="${currentStyles.join(';')}">${escapeHtml(textSegment)}</span>`;
      } else {
        result += escapeHtml(textSegment);
      }
    }

    // Parse the ANSI codes
    const codes = match[1].split(';');
    for (const code of codes) {
      if (code === '0') {
        // Reset
        currentStyles = [];
      } else if (ANSI_COLORS[code]) {
        currentStyles.push(ANSI_COLORS[code]);
      }
    }

    lastIndex = match.index + match[0].length;
  }

  // Add remaining text
  if (lastIndex < text.length) {
    const remaining = text.slice(lastIndex);
    if (currentStyles.length > 0) {
      result += `<span style="${currentStyles.join(';')}">${escapeHtml(remaining)}</span>`;
    } else {
      result += escapeHtml(remaining);
    }
  }

  return result;
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

