  '92': 'color: #00ff00', // bright green
  '93': 'color: #ffff00', // bright yellow
  '94': 'color: #0000ff', // bright blue
  '95': 'color: #ff00ff', // bright magenta
  '96': 'color: #00ffff', // bright cyan
  '97': 'color: #ffffff', // bright white
  '1': 'font-weight: bold',
  '3': 'font-style: italic',
  '4': 'text-decoration: underline',
};

